   "source": "from scipy import stats\nfrom sklearn.cluster import DBSCAN\nfrom sklearn.ensemble import IsolationForest\nfrom sklearn.preprocessing import StandardScaler\n\nX = StandardScaler().fit_transform(df.drop(columns='target'))\n\ndef outliers_zscore(X, df, n=20):\n    scores = np.abs(stats.zscore(X)).max(axis=1)\n    return df.iloc[np.argsort(scores)[-n:]]\n\ndef outliers_clustering(X, df, n=20):\n    labels = DBSCAN(eps=3, min_samples=5).fit_predict(X)\n    noise_idx = np.where(labels == -1)[0]\n    return df.iloc[noise_idx[:n]]\n\ndef outliers_isoforest(X, df, n=20):\n    scores = IsolationForest(random_state=0).fit(X).decision_function(X)\n    return df.iloc[np.argsort(scores)[:n]]\n\nzscore_outliers   = outliers_zscore(X, df)\ncluster_outliers  = outliers_clustering(X, df)\nisoforest_outliers = outliers_isoforest(X, df)\n\nprint(f\"Z-Score:          {len(zscore_outliers)} outliers\")\nprint(f\"Clustering:       {len(cluster_outliers)} outliers\")\nprint(f\"Isolation Forest: {len(isoforest_outliers)} outliers\")",
